(window.webpackJsonp=window.webpackJsonp||[]).push([[251],{878:function(n,t){n.exports='\x3c!-- \ntitle: 03-Java基础\nsort: \n--\x3e \n\n> [refer_1](https://blog.csdn.net/yhsnihao/article/details/88697660) [refer_2](https://blog.csdn.net/qq_30993595/article/details/81951361)\n\n## JAVA基础\n\n> 面向对象\n>\n> 编译器将每一个class编译成相应名称的`.class`字节码文件。\n\n## 特性\n\n- 自动回收内存\n\n  `System.gc();`\n\n## 关键字\n\n- `static`\n\n  > 无论一个类实例化多少对象，它的静态变量只有一份拷贝。\n  >\n  > `main()`方法是静态的，执行时不会创建所在类的实例对象\n\n### 变量\n\n> 函数中变量分配栈内存，调用结束后自动释放。\n>\n> `new`定义的对象或数组分配堆内存，由java虚拟机自动回收\n\n```java\n// 数组不可指定大小\nint i[] = {1,2,3,4};\nint i[] = new x[num];\nint i[] = new x[]{1,2,3,4};\n// 多维数组\n// 本质是数组中的数组\nint x[][];\nx = new int[3][];\nx[0] = new int[3];\nx[1] = new int[2];\n// x[2]未赋值，指向null\n```\n\n## 基础语句\n\n```java\n// 高级for循环\nint for_array[] = { 2, 3, 5, 7, 11 };\nfor (int num : for_array) {\n    System.out.println(num);\n}\n// 三目运算\n(a>b)?c:d;\n```\n\n\n### 枚举\n\n```java\nclass FreshJuice {\n   enum FreshJuiceSize{ SMALL, MEDIUM , LARGE }\n   FreshJuiceSize size;\n}\n \npublic class FreshJuiceTest {\n   public static void main(String[] args){\n      FreshJuice juice = new FreshJuice();\n      juice.size = FreshJuice.FreshJuiceSize.MEDIUM  ;\n   }\n}\n```\n\n## 面向对象\n\n### 函数重载\n\n```java\nclass Person {\n\tString name="fzf";\n\tint age = 18;\n\tpublic void introduce()\n\t{\n\t\tSystem.out.println("My name is "+name+" and I\'m "+age+" years old.FUN1");\n\t}\n    \n    //重载introduce()函数\n\tpublic void introduce(String per_name)\n\t{\n\t\tname = per_name;\n\t\tSystem.out.println("My name is "+name+" and I\'m "+age+" years old.FUN2");\n\t}\n    \n    //重载introduce()函数\n\tpublic void introduce(String per_name,int per_age)\n\t{\n\t\tname = per_name;\n\t\tage = per_age;\n\t\tSystem.out.println("My name is "+name+" and I\'m "+age+" years old.FUN3");\n\t}\n}\n\npublic class demo {\n\tpublic static void main(String[] args) {\n\t\tPerson person_test = new Person();\n\t\tperson_test.introduce();\n\t\tperson_test.introduce("tom");\n\t\tperson_test.introduce("cat",19);\n\t\t\n\t}\n```\n\n### 构造函数\n\n> 无返回值，创建实例时执行初始化\n\n```java\nclass Person {\n\t// 显示初始化\n\tprivate String per_name = "unknow";\n\tprivate int per_age = 0;\n\n\t// 构造方法，无返回类型\n\tpublic Person() {\n\t\tSystem.out.println("My name is " + per_name);\n\t}\n\n\tpublic Person(String person_name) {\n\t\tper_name = person_name;\n\t\tSystem.out.println("My name is " + per_name);\n\t}\n\n\tpublic Person(String person_name, int person_age) {\n\t\tper_name = person_name;\n\t\tper_age = person_age;\n\t\tSystem.out.println("My name is " + per_name + " and I\'m " + per_age + " years old");\n\t}\n\n\tpublic void Person() {\n\t\tSystem.out.println("I\'m not Constructor,you can call me anytime and anywhere!");\n\t}\n}\n\npublic class demo {\n\tpublic static void main(String arg[]) {\n\t\tPerson p1 = new Person();\n\t\tPerson p2 = new Person("Tom", 18);\n\t\tPerson p3 = new Person("Victor");\n\t\tp1.Person();\n\t}\n\n}\n/*\nMy name is unknow\nMy name is Tom and I\'m 18 years old\nMy name is Victor\nI\'m not Constructor,you can call me anytime and anywhere!\n```\n\n### this\n\n> 指向对象在堆内存中的首地址\n\n```java\nclass A\n{\n\tpublic void fun1()\n\t{\n\t}\n\tpublic void fun2()\n\t{\n\t\tA a2 = new A();\n        // 调用a2的func1()方法\n        a2.fun1();\n        // 调用实例的func()方法\n\t\tthis.fun1();\n\t}\n\n\tpublic static void main(String arg[])\t\t//main函数\n\t{\n        // 实例化A类\n\t\tA a1 = new A();\n        // 对象a1调用fun2()方法\n\t\ta1.fun2();\t\t\n\t}\n}\n```\n\n```java\nclass Person\n{\n\tprivate String name;\n\tpublic shout(String name)\n\t{\n        // 对象的属性->方法中的局部变量\n\t\tthis.name=name;\n\t\tSystem.out.println("My name is "+name);\n\t}\n}\n```\n\n> 调用构造方法\n\n```java\nclass Test\n{\n\tpublic Test()\n\t{\n\t\tthis("function2");\n\t}\n\tpublic Test(String m)\n\t{\n\t\tSystem.out.println(m+" is running");\n\t}\n\n\tpublic static void main (String arg[])\n\t{\n\t\tTest t = new Test();\n\t}\n}\n/*\nfunction2 is running\n```\n\n### 对象的强制类型转换\n\n```java\nclass A\n{\n\tpublic void func1()\n\t{\n\t\tSystem.out.println("A func1 is calling");\n\t}\n\t\tpublic void func1()\n\t{\n\t\tSystem.out.println("A func2 is calling");\n\t}\n}\n\nclass B extends A\n{\n\tpublic void func1()\n\t{\n\t\tSystem.out.println("B func1 is calling");\n\t}\n\tpublic void func3()\n\t{\n\t\tSystem.out.println("B func3 is calling");\n\t}\n}\n\nclass Test\n{\n\tpublic static void main(String args[])\n\t{\n\t\tcallA(new B());\t\t\t//将类B传递给callA函数\n\t}\n\tpublic static void callA(A a)\t\t//函数接受一个类A的对象作为参数\n\t{\n\t\ta.func1();\n\t\ta.func2();\n\t}\n}\n```\n\n\n\n'}}]);